#!/usr/bin/env Rscript

## Plot overhead percentiles from hriblt benchmark TSV output.
##
## Usage: plot-overhead.r [input.tsv] [output.pdf]
##
## The input TSV should have columns: trial, set_size, diff_size, success, coded_symbols, overhead
## Generated by: cargo run -p hriblt --bin hriblt-bench --features bin -- --tsv ...

library(dplyr)
library(ggplot2)
library(readr)
library(stringr)

args <- commandArgs(trailingOnly = TRUE)
input <- "overhead.tsv"
output <- NULL

if (length(args) > 0) {
  if (args[1] %in% c("-h", "--help")) {
    cat("
Usage: plot-overhead.r [input.tsv] [output.pdf]

  Plot overhead percentiles (p0, p25, p50, p75, p99) vs diff_size from benchmark TSV.

  The input TSV should be generated by hriblt-bench with --tsv flag:

      cargo run -p hriblt --bin hriblt-bench --features bin -- \\
          --trials 1000 --diff-size '1..101' --diff-mode incremental --tsv > overhead.tsv

  Example usage:

      plot-overhead.r overhead.tsv overhead.pdf

")
    quit(status = 0)
  }
  input <- args[1]
}

if (length(args) > 1) {
  output <- args[2]
} else {
  output <- str_replace(input, "\\.(tsv|csv)$", ".pdf")
  if (output == input) {
    output <- paste0(input, ".pdf")
  }
}

# Read data
data <- read_tsv(input, show_col_types = FALSE)

# Filter to successful trials with valid overhead
data <- data %>%
  filter(success == TRUE, !is.na(overhead), overhead > 0)

# Compute percentiles per diff_size
stats <- data %>%
  group_by(diff_size) %>%
  summarise(
    p0 = min(overhead),
    p25 = quantile(overhead, 0.25),
    p50 = quantile(overhead, 0.50),
    p75 = quantile(overhead, 0.75),
    p99 = quantile(overhead, 0.99),
    n = n(),
    .groups = "drop"
  )

# Get sample size for title
total_n <- nrow(data)
trials_per_diff <- stats$n[1]

# Create the plot
plot <- ggplot(stats, aes(x = diff_size)) +
  # p0-p99 range (min-max)
  geom_ribbon(aes(ymin = p0, ymax = p99), fill = "#cccccc", alpha = 0.5) +
  # p25-p75 range (interquartile)
  geom_ribbon(aes(ymin = p25, ymax = p75), fill = "#6699cc", alpha = 0.7) +
  # p50 median line
  geom_line(aes(y = p50), color = "#003366", linewidth = 1) +
  # Reference line at y=1 (theoretical minimum)
  geom_hline(yintercept = 1, linetype = "dashed", color = "#999999", alpha = 0.7) +
  # Labels
  labs(
    title = paste0("Overhead vs Diff Size (n = ", trials_per_diff, " trials per diff_size)"),
    subtitle = "coded_symbols / diff_size",
    x = "Diff Size",
    y = "Overhead Multiplier"
  ) +
  # Theme

  theme_minimal() +
  theme(
    plot.title = element_text(size = 14, face = "bold"),
    plot.subtitle = element_text(size = 10, color = "#666666"),
    axis.title = element_text(size = 11),
    panel.grid.minor = element_blank()
  ) +
  # Scales
  scale_y_continuous(
    breaks = scales::breaks_extended(8),
    limits = c(0, NA)
  )

# Add legend manually via annotation
plot <- plot +
  annotate("rect", xmin = -Inf, xmax = Inf, ymin = -Inf, ymax = Inf, fill = NA) +
  labs(caption = "Gray: p0-p99 range | Blue: p25-p75 range | Line: p50 median")

# Save to PDF
pdf(file = output, width = 10, height = 6)
print(plot)
dev.off()

cat(paste0("Output: ", output, "\n"))
